-- Legislacao full-site: tarcisio-gov-sp / SP ALESP / legislacao_mandato_executivo
-- Seed ampliado parcial: Lote A normas de 2026 sancionadas por Tarcisio de Freitas
-- ============================================
-- Fonte oficial: Assembleia Legislativa do Estado de Sao Paulo - Repositorio de Legislacao
-- Artefato: fonte interna de curadoria
-- Coverage: tarcisio-gov-sp-alesp-governador-ampliado-parcial-lote-a-20260506
-- Esta migration NAO escreve em projetos_lei.
-- Esta migration NAO escreve em historico_politico.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  lme_total int;
  target_count int;
  mandato_count int;
  projetos_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'tarcisio-gov-sp';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'tarcisio-gov-sp: candidato ausente neste banco local/CI minimo; seed LME SP ALESP pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO lme_total
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'tarcisio-gov-sp-alesp-governador-ampliado-parcial-lote-a-20260506';

  SELECT count(*) INTO projetos_count
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  IF lme_total NOT IN (1, 62) THEN
    RAISE EXCEPTION 'Pre-condicao tarcisio-gov-sp: esperada 1 row legado atual ou 62 rows idempotentes em LME, encontradas %', lme_total;
  END IF;

  IF lme_total = 62 AND target_count <> 61 THEN
    RAISE EXCEPTION 'Pre-condicao tarcisio-gov-sp: 62 rows LME existentes, mas apenas % com coverage_id alvo', target_count;
  END IF;

  IF projetos_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao tarcisio-gov-sp: projetos_lei deve permanecer 0 rows, encontrado %', projetos_count;
  END IF;

  SELECT count(*) INTO mandato_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND hp.cargo_canonico = 'Governador'
    AND upper(coalesce(hp.estado, '')) = 'SP'
    AND coalesce(hp.periodo_inicio, 9999) <= 2026
    AND coalesce(hp.periodo_fim, 9999) >= 2026;

  IF mandato_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao tarcisio-gov-sp: mandato Governador/SP compativel com 2026 nao encontrado';
  END IF;
END $$;

