    ('lei_sancionada', 'estadual', 'SP', NULL, 'lei', '18.388', 2026, '2026-01-22', 'Reconhece como de relevante interesse cultural do Estado a "Região Turística da Fé" do Vale do Paraíba.', 'TARCÍSIO DE FREITAS', 'titular', 'https://www.al.sp.gov.br/repositorio/legislacao/lei/2026/lei-18388-22.01.2026.html', 'Assembleia Legislativa do Estado de Sao Paulo - Repositorio de Legislacao', 'https://www.al.sp.gov.br/norma/212173', 'ALESP-SP-TARCISIO:212173', '{"source":"ALESP","data_real":true,"fluxo":"Legislacao full-site","case_id":"sp_alesp_lei_18388_2026","curation_batch_id":"tarcisio-gov-sp-alesp-governador-lote-a-20260506","coverage_id":"tarcisio-gov-sp-alesp-governador-ampliado-parcial-lote-a-20260506","coverage_scope":"inventario_ampliado_parcial_sp_alesp_governador_2026_lote_a_20260506","projetos_lei_mixed":false,"historico_politico_id_inferido_por_data":false,"autoridade_papel_basis":"formula_governador_do_estado_e_assinatura_nominal","alesp_norma_id":"212173","alesp_norma_url":"https://www.al.sp.gov.br/norma/212173","alesp_publicacao_url":"https://www.al.sp.gov.br/norma/publicacao/212173","alesp_index_url":"https://www.al.sp.gov.br/norma/resultados?tipoPesquisa=E&page=0&size=1000&idsTipoNorma=9&idsTipoNorma=2&ano=2026","alesp_index_year":2026,"fonte_oficial_verificada_em":"2026-05-06T11:07:41.343Z"}'::jsonb)
), target AS (
  SELECT
    c.id AS candidato_id,
    seed.*,
    (
      SELECT hp.id
      FROM historico_politico hp
      WHERE hp.candidato_id = c.id
        AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
        AND hp.cargo_canonico = 'Governador'
        AND upper(coalesce(hp.estado, '')) = 'SP'
        AND coalesce(hp.periodo_inicio, 9999) <= seed.ano
        AND coalesce(hp.periodo_fim, 9999) >= seed.ano
      ORDER BY hp.periodo_inicio DESC NULLS LAST, hp.id
      LIMIT 1
    ) AS historico_politico_id
  FROM candidatos c
  CROSS JOIN seed_rows seed
  WHERE c.slug = 'tarcisio-gov-sp'
)
INSERT INTO legislacao_mandato_executivo (
  candidato_id,
  historico_politico_id,
  tipo_relacao,
  esfera,
  uf_norma,
  municipio_norma,
  tipo_norma,
  numero,
  ano,
  data_norma,
  ementa,
  signatario,
  autoridade_papel,
  fonte_primaria_url,
  fonte_primaria_titulo,
  fonte_tramitacao_url,
  identificador_fonte,
  metadata
)
SELECT
  target.candidato_id,
  target.historico_politico_id,
  target.tipo_relacao,
  target.esfera,
  target.uf_norma,
  target.municipio_norma,
  target.tipo_norma,
  target.numero,
  target.ano,
  target.data_norma::date,
  target.ementa,
  target.signatario,
  target.autoridade_papel,
  target.fonte_primaria_url,
  target.fonte_primaria_titulo,
  target.fonte_tramitacao_url,
  target.identificador_fonte,
  target.metadata
FROM target
WHERE target.historico_politico_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = target.candidato_id
      AND lme.identificador_fonte = target.identificador_fonte
  );

DO $$
DECLARE
  cand_id uuid;
  v_total integer;
  v_scope integer;
  v_projetos integer;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'tarcisio-gov-sp';
  IF cand_id IS NULL THEN
    RAISE NOTICE 'tarcisio-gov-sp: pos-condicao pulada porque candidato nao existe neste banco local/CI minimo';
    RETURN;
  END IF;

  SELECT count(*) INTO v_total
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO v_scope
  FROM legislacao_mandato_executivo
  WHERE candidato_id = cand_id
    AND metadata->>'coverage_id' = 'tarcisio-gov-sp-alesp-governador-ampliado-parcial-lote-a-20260506'
    AND metadata->>'coverage_scope' = 'inventario_ampliado_parcial_sp_alesp_governador_2026_lote_a_20260506'
    AND signatario = 'TARCÍSIO DE FREITAS'
    AND autoridade_papel = 'titular';

  SELECT count(*) INTO v_projetos
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  IF v_total <> 62 THEN
    RAISE EXCEPTION 'Pos-condicao tarcisio-gov-sp: esperava 62 rows LME totais, encontrei %', v_total;
  END IF;
  IF v_scope <> 61 THEN
    RAISE EXCEPTION 'Pos-condicao tarcisio-gov-sp: esperava 61 rows com coverage/signatario/titular, encontrei %', v_scope;
  END IF;
  IF v_projetos <> 0 THEN
    RAISE EXCEPTION 'Pos-condicao tarcisio-gov-sp: projetos_lei deveria permanecer 0, encontrei %', v_projetos;
  END IF;
  RAISE NOTICE 'Pos-apply tarcisio-gov-sp SP ALESP Lote A: lme=% coverage=% projetos_lei=%', v_total, v_scope, v_projetos;
END $$;
